  ('heelevel3-10ced7e2-moex-00329', 'heelevel3-10ced7e2', 'heelevel3-10ced7e2-moex-110-3082b5f1', 'sub-heelevel3-10ced7e2-04', NULL, 'single_choice', '行政機關依法實施即時強制，造成人民損害之補償，下列何者錯誤？', '["該損失補償，以回復原狀為原則，金錢補償為例外", "對於執行機關所為損失補償之決定不服，可依法提起訴願及行政訴訟", "損失補償，應於知有損失後，2年內向執行機關請求", "人民因執行機關依法實施即時強制，致其財產遭受特別損失，原則得請求補償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:36+00:00", "source_pdf_sha1": "b59c20af004e", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "322", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "人事行政"}'::jsonb, NULL),
